# Reclassify
updates = []
for pid, slug, title, desc in misc:
    text = f"{slug} {title} {desc or ''}".lower()
    matched = False
    for target_slug, keywords in rules:
        for kw in keywords:
            if kw.lower() in text:
                updates.append((cat_map[target_slug], pid))
                matched = True
                break
        if matched:
            break

print(f"Will reclassify {len(updates)} projects")

# Apply updates
for cat_id, pid in updates:
    c.execute("UPDATE Project SET categoryId = ? WHERE id = ?", (cat_id, pid))

conn.commit()

# Show new distribution
c.execute("""
    SELECT c.name, COUNT(p.id) 
    FROM Category c 
    LEFT JOIN Project p ON c.id = p.categoryId 
    GROUP BY c.id 
    ORDER BY COUNT(p.id) DESC
""")
for name, count in c.fetchall():
    print(f"{name}: {count}")

conn.close()
